"use client";

/**
 * Opener for the `multiFileSmartCodeEditorWindow` overlay.
 *
 * - `useOpenMultiFileSmartCodeEditorWindow()` — imperative hook. Call to open with typed options;
 *   returns a handle with a `close()` method.
 * - `<MultiFileSmartCodeEditorWindowController />` — declarative wrapper. Mount to open,
 *   unmount to close. Equivalent ergonomics to rendering a normal component.
 *
 * Generated by scripts/generate-overlay-controller.ts (`openers` mode).
 * Hand-edit freely after the initial seed; the script will not re-emit a
 * file that already exists unless invoked with --force.
 */

import { useCallback, useEffect } from "react";
import { useAppDispatch } from "@/lib/redux/hooks";
import { closeOverlay, openOverlay } from "@/lib/redux/slices/overlaySlice";

const OVERLAY_ID = "multiFileSmartCodeEditorWindow" as const;

export interface OpenMultiFileSmartCodeEditorWindowOptions {
  /** Optional stable instance id. Omit to spawn a fresh instance. */
  instanceId?: string;
  windowInstanceId: string;
  callbackGroupId?: string | null;
  agentId: string;
  /** TODO: tighten to `CodeFile[]` once that type is imported. */
  files: unknown;
  initialActiveFile?: string | null;
  title?: string | null;
  /** TODO: tighten to `"on" | "off"` once that type is imported. */
  defaultWordWrap?: unknown;
  autoFormatOnOpen?: boolean;
  variables?: Record<string, unknown> | null;
}

export interface MultiFileSmartCodeEditorWindowHandle {
  instanceId: string;
  close: () => void;
}

export function useOpenMultiFileSmartCodeEditorWindow() {
  const dispatch = useAppDispatch();
  return useCallback(
    (opts: OpenMultiFileSmartCodeEditorWindowOptions): MultiFileSmartCodeEditorWindowHandle => {
      const instanceId = opts.instanceId ?? `multiFileSmartCodeEditorWindow-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      dispatch(
        openOverlay({
          overlayId: OVERLAY_ID,
          instanceId,
          data: {
            windowInstanceId: opts.windowInstanceId,
            callbackGroupId: opts.callbackGroupId,
            agentId: opts.agentId,
            files: opts.files,
            initialActiveFile: opts.initialActiveFile,
            title: opts.title,
            defaultWordWrap: opts.defaultWordWrap,
            autoFormatOnOpen: opts.autoFormatOnOpen,
            variables: opts.variables,
          },
        }),
      );
      return {
        instanceId,
        close: () => dispatch(closeOverlay({ overlayId: OVERLAY_ID, instanceId })),
      };
    },
    [dispatch],
  );
}

/**
 * Declarative form. Renders nothing visible; opens the overlay on mount,
 * closes it on unmount. Use this when a caller wants to express overlay
 * state declaratively (the way they'd render a normal component).
 */
export function MultiFileSmartCodeEditorWindowController(props: OpenMultiFileSmartCodeEditorWindowOptions): null {
  const open = useOpenMultiFileSmartCodeEditorWindow();
  useEffect(() => {
    const handle = open(props);
    return () => handle.close();
  }, [open, props.windowInstanceId, props.callbackGroupId, props.agentId, props.files, props.initialActiveFile, props.title, props.defaultWordWrap, props.autoFormatOnOpen, props.variables]);
  return null;
}
